import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api/axios';

export default function Register() {
  const { login } = useAuth();
  const navigate  = useNavigate();
  const [form, setForm]       = useState({ teamName: '', slug: '', email: '', password: '' });
  const [error, setError]     = useState('');
  const [loading, setLoading] = useState(false);

  const handle = e => setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async e => {
    e.preventDefault();
    setLoading(true);
    try {
      const { data } = await api.post('/api/auth/register', form);
      login(data);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed');
      setLoading(false);
    }
  };

  const inputCls = "w-full px-3.5 py-2.5 text-sm rounded-xl bg-[#e5e7eb] dark:bg-gh-canvas border border-transparent focus:border-brand-blue focus:outline-none focus:ring-2 focus:ring-brand-blue/20 text-gray-800 dark:text-gh-text placeholder-gray-400 dark:placeholder-gh-dim transition-all";

  const fields = [
    { name: 'teamName', label: 'Team Name',  placeholder: 'Acme Corp',   type: 'text' },
    { name: 'slug',     label: 'Team Slug',  placeholder: 'acme-corp',   type: 'text' },
    { name: 'email',    label: 'Email',      placeholder: 'admin@acme.com', type: 'email' },
    { name: 'password', label: 'Password',   placeholder: 'At least 6 characters', type: 'password', minLength: 6, extra: 'Minimum 6 characters required' },
  ];

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#f4f5f7] dark:bg-gh-canvas p-4">
      <div className="w-full max-w-sm bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border p-8">
        {/* Logo */}
        <div className="flex flex-col items-center mb-7">
          <div className="w-10 h-10 rounded-xl bg-brand-blue flex items-center justify-center mb-3">
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M22 12h-4l-3 9L9 3l-3 9H2"/>
            </svg>
          </div>
          <h1 className="text-xl font-bold text-gray-900 dark:text-gh-text">Create your team</h1>
          <p className="text-sm text-gray-500 dark:text-gh-muted mt-1">Start monitoring in under a minute</p>
        </div>

        {error && (
          <div className="mb-4 flex items-center gap-2 px-3 py-2.5 bg-red-50 dark:bg-transparent text-red-600 dark:text-red-400 border border-red-200 dark:border-red-400/30 rounded-xl text-sm">
            <span>⚠</span> {error}
          </div>
        )}

        <form onSubmit={submit} className="space-y-3.5">
          {fields.map(f => (
            <div key={f.name}>
              <div className="flex items-center justify-between mb-1.5">
                <label className="block text-sm font-medium text-gray-700 dark:text-gh-muted">{f.label}</label>
                {f.extra && <span className="text-[11px] text-gray-400 dark:text-gh-dim">{f.extra}</span>}
              </div>
              <input name={f.name} type={f.type} minLength={f.minLength} placeholder={f.placeholder} onChange={handle} required className={inputCls} />
            </div>
          ))}
          <button
            type="submit" disabled={loading}
            className="w-full py-2.5 rounded-xl text-sm font-semibold text-white bg-brand-blue hover:bg-brand-blue-h dark:bg-gh-green dark:hover:bg-gh-green-h transition-colors flex items-center justify-center gap-2 mt-1"
          >
            {loading
              ? <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full" style={{ animation: 'spin 0.6s linear infinite' }} />
              : 'Create account'}
          </button>
        </form>

        <p className="mt-5 text-center text-sm text-gray-500 dark:text-gh-muted border-t border-gray-100 dark:border-gh-border pt-5">
          Already have an account?{' '}
          <Link to="/login" className="text-brand-blue font-medium hover:underline">Sign in</Link>
        </p>
      </div>
    </div>
  );
}
